import React from 'react'; 
import { useAppSelector } from '../../libraries/hook';
const Content = () => {
    const myTest = useAppSelector((state) => state.test);
    console.log('myTest', myTest);
    return (
        <main>
            <h2>This is content area</h2>
            <p>Test value from Redux store: {myTest.items}</p>
        </main>
    );
}

export default Content;
